changeSet.sql:
-- Journal Entries CREATE TABLE journals ( id bigint not null, m_account_id BIGINT not null, serialId VARCHAR(50) UNIQUE NOT NULL, name VARCHAR(50) NOT NULL, description TEXT, is_active BOOLEAN DEFAULT TRUE, CONSTRAINT journals_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS journals_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY journals.id;
CREATE TABLE journal_entries ( id bigint not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, serial_id VARCHAR(50) UNIQUE NOT NULL, journal_id INTEGER REFERENCES journals(id), entry_number VARCHAR(50) UNIQUE NOT NULL, description TEXT, entry_date DATE NOT NULL, fiscal_period_id INTEGER REFERENCES fiscal_periods(id), is_posted BOOLEAN DEFAULT FALSE, CONSTRAINT journal_entries_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS journal_entries_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY journal_entries.id;
CREATE TABLE journal_entry_lines ( id bigint not null, journal_entry_id INTEGER REFERENCES journal_entries(id), partner_id BIGINT , account_id INTEGER REFERENCES fin_accounts(id), description TEXT, debit_amount DECIMAL(15,2) DEFAULT 0, credit_amount DECIMAL(15,2) DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT journal_entry_lines_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS journal_entry_lines_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY journal_entry_lines.id;
